class PaymentCard {
  final String number;
  final String expiryMonth;
  final String expiryYear;
  final String cvv;
  final String holderName;
  final String? billingAddress;
  final String? zipCode;

  PaymentCard({
    required this.number,
    required this.expiryMonth,
    required this.expiryYear,
    required this.cvv,
    required this.holderName,
    this.billingAddress,
    this.zipCode,
  });

  bool isValid() {
    return _validateCardNumber(number) &&
        _validateExpiry(expiryMonth, expiryYear) &&
        _validateCVV(cvv);
  }

  bool _validateCardNumber(String number) {
    final cleaned = number.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;

    int sum = 0;
    bool alternate = false;
    for (int i = cleaned.length - 1; i >= 0; i--) {
      int digit = int.parse(cleaned[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  bool _validateExpiry(String month, String year) {
    final now = DateTime.now();
    final expMonth = int.tryParse(month);
    final expYear = int.tryParse(year);

    if (expMonth == null || expYear == null) return false;
    if (expMonth < 1 || expMonth > 12) return false;

    final fullYear = expYear < 100 ? 2000 + expYear : expYear;
    final expiryDate = DateTime(fullYear, expMonth + 1, 0);

    return expiryDate.isAfter(now);
  }

  bool _validateCVV(String cvv) {
    return cvv.length >= 3 && cvv.length <= 4 && int.tryParse(cvv) != null;
  }

  String getCardType() {
    final cleaned = number.replaceAll(RegExp(r'\s+'), '');
    if (RegExp(r'^4').hasMatch(cleaned)) return 'Visa';
    if (RegExp(r'^5[1-5]').hasMatch(cleaned)) return 'Mastercard';
    if (RegExp(r'^3[47]').hasMatch(cleaned)) return 'American Express';
    if (RegExp(r'^6(?:011|5)').hasMatch(cleaned)) return 'Discover';
    return 'Unknown';
  }

  Map<String, dynamic> toSecureJson() {
    return {
      'last4': number.substring(number.length - 4),
      'cardType': getCardType(),
      'expiryMonth': expiryMonth,
      'expiryYear': expiryYear,
      'holderName': holderName,
    };
  }
}

