    required String transactionId,
    required double amount,
  });

  Future<bool> verifyPayment(String transactionId);
}

class StripePaymentGateway implements PaymentGateway {
  final PaymentConfig config;
  final String baseUrl;

  StripePaymentGateway(this.config)
      : baseUrl = config.sandboxMode
            ? 'https://api.stripe.com/v1'
            : 'https://api.stripe.com/v1';

  @override
  Future<PaymentTransaction> processPayment({
    required String userId,
    required double amount,
    required String currency,
    required Map<String, dynamic> paymentDetails,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      final amountInCents = (amount * 100).toInt();

      final paymentIntentResponse = await http.post(
        Uri.parse('$baseUrl/payment_intents'),
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'amount': amountInCents.toString(),
          'currency': currency.toLowerCase(),
          'payment_method_types[]': 'card',
          'metadata[userId]': userId,
          if (metadata != null)
            ...metadata.map((key, value) => MapEntry('metadata[$key]', value.toString())),
        },
      );

      if (paymentIntentResponse.statusCode != 200) {
        throw Exception('Failed to create payment intent: ${paymentIntentResponse.body}');
      }

      final paymentIntent = json.decode(paymentIntentResponse.body);
      final paymentIntentId = paymentIntent['id'];

      final confirmResponse = await http.post(
        Uri.parse('$baseUrl/payment_intents/$paymentIntentId/confirm'),
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'payment_method': paymentDetails['paymentMethodId'],
        },
      );

      final confirmedIntent = json.decode(confirmResponse.body);
      final status = confirmedIntent['status'];

      return PaymentTransaction(
        id: paymentIntentId,
        userId: userId,
        amount: amount,
        currency: currency,
        paymentMethod: PaymentMethod.stripe,
        status: _mapStripeStatus(status),
        type: TransactionType.purchase,
        timestamp: DateTime.now(),
        metadata: metadata ?? {},
        receiptUrl: confirmedIntent['charges']?['data']?[0]?['receipt_url'],
      );
    } catch (e) {
      return PaymentTransaction(
        id: DateTime.now().millisecondsSinceEpoch.toString(),
        userId: userId,
        amount: amount,
        currency: currency,
        paymentMethod: PaymentMethod.stripe,
        status: PaymentStatus.failed,
        type: TransactionType.purchase,
        timestamp: DateTime.now(),
        metadata: metadata ?? {},
        errorMessage: e.toString(),
      );
    }
  }

  @override
  Future<PaymentTransaction> refundPayment({
    required String transactionId,
    required double amount,
  }) async {
    try {
      final amountInCents = (amount * 100).toInt();

      final response = await http.post(
        Uri.parse('$baseUrl/refunds'),
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'payment_intent': transactionId,
          'amount': amountInCents.toString(),
        },
      );

      if (response.statusCode != 200) {
        throw Exception('Failed to process refund: ${response.body}');
      }

      final refund = json.decode(response.body);

      return PaymentTransaction(
        id: refund['id'],
        userId: '',
        amount: amount,
        currency: refund['currency'].toUpperCase(),
        paymentMethod: PaymentMethod.stripe,
        status: PaymentStatus.refunded,
        type: TransactionType.refund,
        timestamp: DateTime.now(),
        metadata: {'originalTransactionId': transactionId},
      );
    } catch (e) {
      throw Exception('Refund failed: $e');
    }
  }

  @override
  Future<bool> verifyPayment(String transactionId) async {
    try {
      final response = await http.get(
        Uri.parse('$baseUrl/payment_intents/$transactionId'),
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
        },
      );

      if (response.statusCode == 200) {
        final paymentIntent = json.decode(response.body);
        return paymentIntent['status'] == 'succeeded';
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  PaymentStatus _mapStripeStatus(String status) {
    switch (status) {
      case 'succeeded':
        return PaymentStatus.completed;
      case 'processing':
        return PaymentStatus.processing;
      case 'requires_payment_method':
      case 'requires_confirmation':
      case 'requires_action':
        return PaymentStatus.pending;
      case 'canceled':
        return PaymentStatus.cancelled;
      default:
        return PaymentStatus.failed;
    }
  }
}

